'use client'
import React, { useState } from 'react';
import { useBudget } from '@/context/BudgetContext';
import { User, Lock, ArrowRight, Loader, ShieldCheck, Wallet, AlertTriangle } from 'lucide-react';
import { GoogleLogin } from '@react-oauth/google';

import { useRouter } from 'next/navigation';

const Login: React.FC = () => {
    const { login, loginWithGoogle } = useBudget();
    const router = useRouter();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');

        try {
            const success = await login(username, password);
            if (success) {
                router.push('/dashboard');
            } else {
                setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
            }
        } catch (err: any) {
            console.error("Login Error Payload:", err);
            setError(`เกิดข้อผิดพลาดในการเข้าสู่ระบบ: ${err.message || err.toString()}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-[#E6F4FA] to-white relative overflow-hidden font-kanit">
            {/* Background Decorations */}
            <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-primary-100/30 rounded-full blur-3xl"></div>
            <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-primary-200/20 rounded-full blur-3xl"></div>

            <div className="w-full max-w-6xl h-[700px] flex bg-white/80 backdrop-blur-2xl rounded-[48px] shadow-[0_40px_100px_rgba(0,165,227,0.15)] border border-white overflow-hidden animate-in fade-in zoom-in-95 duration-1000 relative z-10">
                {/* Branding Section - KTB Next Blue Gradient */}
                <div className="hidden lg:flex lg:w-1/2 p-16 bg-gradient-to-br from-primary-600 via-primary-500 to-primary-700 items-center justify-center relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-96 h-96 bg-white/10 rounded-full -mr-24 -mt-24 blur-3xl animate-pulse"></div>
                    <div className="absolute bottom-0 left-0 w-80 h-80 bg-primary-400/20 rounded-full -ml-24 -mb-24 blur-3xl"></div>

                    <div className="relative z-10 text-center space-y-10 max-w-sm">
                        <div className="inline-flex p-6 rounded-[32px] bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl transition-transform hover:scale-110 duration-500">
                            <Wallet className="w-20 h-20 text-white" />
                        </div>
                        <div className="space-y-4">
                            <h2 className="text-5xl font-extrabold text-white tracking-tighter leading-tight italic drop-shadow-lg">
                                SMART BUDGET
                            </h2>
                            <p className="text-primary-50 text-lg font-medium tracking-wide opacity-90 leading-relaxed">
                                ยกระดับการบริหารงบประมาณด้วยเทคโนโลยี <br /> Digital Trust Platform ที่แม่นยำที่สุด
                            </p>
                        </div>
                        <div className="flex justify-center gap-3 pt-4">
                            {[1, 2, 3].map((i) => (
                                <div key={i} className={`h-1.5 rounded-full transition-all duration-500 ${i === 1 ? 'w-12 bg-white' : 'w-4 bg-white/30'}`}></div>
                            ))}
                        </div>
                    </div>
                    <div className="absolute bottom-8 left-12 text-[10px] text-white/30 tracking-[0.2em] font-mono uppercase">
                        Secured by DCC Platform • v2.0.0
                    </div>
                </div>

                {/* Form Section */}
                <div className="w-full lg:w-1/2 p-12 lg:p-20 flex flex-col justify-center bg-white/40">
                    <div className="max-w-md mx-auto w-full space-y-10">
                        <div className="space-y-3">
                            <h3 className="text-4xl font-extrabold text-gray-900 tracking-tight">เข้าสู่ระบบ</h3>
                            <p className="text-gray-500 font-semibold tracking-wide flex items-center gap-2">
                                <span className="w-6 h-1 bg-primary-500 rounded-full"></span>
                                จัดการงบประมาณ DCC อย่างมือโปร
                            </p>
                        </div>

                        {error && (
                            <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300">
                                <div className="p-2 bg-red-500 rounded-lg">
                                    <AlertTriangle className="w-4 h-4 text-white" />
                                </div>
                                <p className="text-sm font-bold text-red-600">{error}</p>
                            </div>
                        )}

                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="space-y-5">
                                <div className="space-y-2">
                                    <label className="text-[11px] font-extrabold text-gray-400 uppercase tracking-[0.2em] ml-1">ชื่อผู้ใช้งาน</label>
                                    <div className="relative group">
                                        <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                                            <User className="h-5 w-5 text-gray-400 group-focus-within:text-primary-500 transition-colors" />
                                        </div>
                                        <input
                                            type="text"
                                            required
                                            value={username}
                                            onChange={(e) => setUsername(e.target.value)}
                                            className="block w-full pl-12 pr-5 py-4 bg-gray-50/50 border-2 border-transparent focus:border-primary-500 focus:bg-white rounded-[20px] text-gray-900 font-bold placeholder:text-gray-400 placeholder:font-medium transition-all duration-300 shadow-sm focus:shadow-xl focus:shadow-primary-500/10"
                                            placeholder="ระบุชื่อผู้ใช้งาน"
                                            disabled={isLoading}
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[11px] font-extrabold text-gray-400 uppercase tracking-[0.2em] ml-1">รหัสผ่าน</label>
                                    <div className="relative group">
                                        <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                                            <Lock className="h-5 w-5 text-gray-400 group-focus-within:text-primary-500 transition-colors" />
                                        </div>
                                        <input
                                            type="password"
                                            required
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            className="block w-full pl-12 pr-5 py-4 bg-gray-50/50 border-2 border-transparent focus:border-primary-500 focus:bg-white rounded-[20px] text-gray-900 font-bold placeholder:text-gray-400 placeholder:font-medium transition-all duration-300 shadow-sm focus:shadow-xl focus:shadow-primary-500/10"
                                            placeholder="••••••••"
                                            disabled={isLoading}
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-4">
                                <button
                                    type="submit"
                                    disabled={isLoading}
                                    className="w-full flex items-center justify-center py-4.5 px-6 rounded-[20px] bg-gradient-to-r from-primary-600 to-primary-500 hover:from-primary-500 hover:to-primary-400 text-white font-extrabold text-lg shadow-xl shadow-primary-500/30 hover:shadow-primary-500/40 transform hover:-translate-y-1 active:scale-95 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed group relative overflow-hidden"
                                >
                                    {isLoading ? (
                                        <Loader className="w-6 h-6 animate-spin" />
                                    ) : (
                                        <span className="relative z-10 flex items-center">
                                            เข้าสู่ระบบ
                                            <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                                        </span>
                                    )}
                                    <div className="absolute inset-0 bg-gradient-to-r from-white/0 via-white/20 to-white/0 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000"></div>
                                </button>

                                <div className="relative py-2">
                                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-100"></div></div>
                                    <div className="relative flex justify-center text-[10px] font-extrabold text-gray-400 uppercase tracking-widest bg-transparent"><span className="px-4">หรือดำเนินการด้วย</span></div>
                                </div>

                                <div className="flex justify-center transform scale-105 transition-transform hover:scale-110">
                                    <GoogleLogin
                                        onSuccess={async (credentialResponse) => {
                                            if (credentialResponse.credential) {
                                                setIsLoading(true);
                                                try {
                                                    const success = await loginWithGoogle(credentialResponse.credential);
                                                    if (success) router.push('/dashboard');
                                                } catch (err) {
                                                    setError('Google Sign-In Error');
                                                } finally {
                                                    setIsLoading(false);
                                                }
                                            }
                                        }}
                                        onError={() => setError('Google Sign-In Failed')}
                                        shape="pill"
                                        theme="outline"
                                        size="large"
                                    />
                                </div>
                            </div>
                        </form>

                        <div className="pt-8 text-center sm:text-left border-t border-gray-50 flex items-center justify-between">
                            <p className="text-[10px] font-bold text-gray-300 tracking-[0.2em] uppercase">
                                © 2026 DCC DIGITAL TRUST
                            </p>
                            <div className="flex gap-4">
                                <div className="w-2 h-2 rounded-full bg-primary-100 italic font-black text-primary-500 animate-pulse"></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;
